mapper.update:
update ingestion_jobs
set status = #{succeededStatus},
    finished_at = #{finishedAt},
    next_retry_at = null,
    last_error = null,
    updated_at = now()
where id = #{jobId}
  and status = #{runningStatus}
  and worker_id = #{workerId}

update ingestion_jobs
set status = #{failedStatus},
    retry_count = retry_count + 1,
    finished_at = #{finishedAt},
    next_retry_at = null,
    last_error = #{lastError},
    updated_at = now()
where id = #{jobId}
  and status = #{runningStatus}
  and worker_id = #{workerId}
